\displaystyle{\begin{aligned}
   {\frac{3}{yx-2}-\frac{6yx}{y^{2}x^{2}-4}} 
      \amp = {\frac{3}{yx-2}}-\frac{6 y x}{(y x - 2)(y x + 2)} \\
      \amp = \frac{3\cdot({yx+2})}{({yx-2})\cdot({yx+2})} -\frac{6 y x}{(y x - 2)(y x + 2)} \\
      \amp = \frac{{3\mathopen{}\left(yx+2\right)-6yx}}{(yx - 2)(yx + 2)} \\
      \amp = \frac{{3yx+6-6yx}}{(yx - 2)(yx + 2)} \\
      \amp = \frac{{-3yx+6}}{(yx - 2)(yx + 2)} \\
      \amp = \frac{{-3\mathopen{}\left(yx-2\right)}}{(yx - 2)(yx + 2)} \\
      \amp = {-\frac{3}{yx+2}}
\end{aligned}
